import React from 'react';

/**
 * Organizo logo — Modern event ticket design with gradient. Adapts to navbar/footer.
 */
export default function OrganizoLogo({ className = '', size = 32 }) {
  return (
    <svg
      className={className}
      width={size}
      height={size}
      viewBox="0 0 40 40"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
    >
      <defs>
        <linearGradient id="logoGradient" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#8b5cf6" />
          <stop offset="50%" stopColor="#a78bfa" />
          <stop offset="100%" stopColor="#c4b5fd" />
        </linearGradient>
      </defs>
      {/* Ticket shape with perforated edges */}
      <path
        d="M8 6C6.89543 6 6 6.89543 6 8V14C6 14.5523 6.44772 15 7 15C7.55228 15 8 15.4477 8 16V24C8 24.5523 7.55228 25 7 25C6.44772 25 6 25.4477 6 26V32C6 33.1046 6.89543 34 8 34H32C33.1046 34 34 33.1046 34 32V26C34 25.4477 33.5523 25 33 25C32.4477 25 32 24.5523 32 24V16C32 15.4477 32.4477 15 33 15C33.5523 15 34 14.5523 34 14V8C34 6.89543 33.1046 6 32 6H8Z"
        fill="url(#logoGradient)"
        stroke="url(#logoGradient)"
        strokeWidth="1.5"
      />
      {/* Stylized "O" letter */}
      <circle cx="20" cy="20" r="7" fill="none" stroke="white" strokeWidth="2" opacity="0.9" />
      <circle cx="20" cy="20" r="4" fill="white" opacity="0.9" />
      {/* Decorative dots */}
      <circle cx="12" cy="12" r="1.5" fill="white" opacity="0.7" />
      <circle cx="28" cy="12" r="1.5" fill="white" opacity="0.7" />
      <circle cx="12" cy="28" r="1.5" fill="white" opacity="0.7" />
      <circle cx="28" cy="28" r="1.5" fill="white" opacity="0.7" />
    </svg>
  );
}
